<template><div class="message" :class="item.sender"><div class="message-row"><div class="message-avatar"><img v-if="item.senderAvatar" :src="item.senderAvatar" alt=""/><span v-else>{{initial}}</span></div><div class="message-body"><strong>{{item.senderName||fallbackName}}</strong><div class="bubble"><a v-if="item.type==='image'" :href="item.url" target="_blank"><img :src="item.thumbnailUrl||item.url" :alt="item.fileName||'图片'" style="max-width:240px;max-height:240px;border-radius:8px"></a><video v-else-if="item.type==='video'" :src="item.url" :poster="item.thumbnailUrl" controls preload="metadata" style="max-width:280px"></video><a v-else-if="item.type==='file'" :href="item.url" target="_blank">📎 {{item.fileName||item.content}} ({{size}})</a><div v-else-if="item.type==='product_card'" class="card-message"><img v-if="item.card?.cover" :src="item.card.cover"><b>{{item.card?.title}}</b><span>¥{{item.card?.price}} · ID {{item.card?.productId}}</span><a :href="'/products/'+item.card?.productId">查看商品</a></div><div v-else-if="item.type==='order_card'" class="card-message"><b>订单 {{item.card?.orderNo}}</b><span>{{item.card?.productTitle}} · ¥{{item.card?.amount}}</span><span>{{item.card?.statusText}} · {{item.card?.createdAt}}</span><a :href="'/orders/'+item.card?.orderId">查看订单</a></div><template v-else>{{item.content}}</template></div><small v-if="item.sender==='seller'">{{item.readText || (item.read?'已读':'未读')}}</small></div></div></div></template><script setup lang="ts">import{computed}from'vue';const props=defineProps<{item:any}>();const fallbackName=computed(()=>props.item.sender==='seller'?'卖家':'买家');const initial=computed(()=>(props.item.senderName||fallbackName.value).slice(0,1));const size=computed(()=>props.item.size?`${(props.item.size/1024/1024).toFixed(1)} MB`:'')</script>
